theme.stylesheet:
/* ── Window frame ────────────────────────────────────────────────────────── */
/* Aqua rounds only the top corners; the native layer mirrors the radius for
   the OS shadow, so the CSS shape must match. */
[data-theme="aqua"] [data-part="window"] {
  border-radius: var(--window-radius) var(--window-radius) 0 0;
}

/* ── Titlebar ────────────────────────────────────────────────────────────── */
[data-theme="aqua"] [data-part="titlebar"] {
  background: var(--titlebar-bg);
  border-bottom: 1px solid var(--border-strong);
  color: var(--titlebar-fg);
}

[data-theme="aqua"] [data-part="title"] {
  font-weight: bold;
  text-shadow: var(--x-aqua-emboss);
  padding: 0 8px;
}

[data-theme="aqua"] [data-part="title-icon"] {
  margin-right: 4px;
  color: var(--fg-muted);
}

/* Unfocused windows lose the gloss and go matte — the signature Aqua cue. */
[data-theme="aqua"] [data-part="window"][data-focused="false"] [data-part="titlebar"] {
  background: var(--titlebar-bg-inactive);
  color: var(--titlebar-fg-inactive);
}
[data-theme="aqua"] [data-part="window"][data-focused="false"] [data-part="title"] {
  text-shadow: none;
}

/* ── Traffic lights ──────────────────────────────────────────────────────── */
[data-theme="aqua"] [data-part="controls"] {
  gap: 8px;
  padding: 0 8px;
}

[data-theme="aqua"] [data-part="control"] {
  width: 13px;
  height: 13px;
  border-radius: 50%;
  border: 1px solid;
  padding: 0;
}

[data-theme="aqua"] [data-part="control"][data-action="close"] {
  background: var(--x-aqua-gel-close);
  border-color: #9a2b22;
}
[data-theme="aqua"] [data-part="control"][data-action="minimize"] {
  background: var(--x-aqua-gel-minimize);
  border-color: #97700f;
}
[data-theme="aqua"] [data-part="control"][data-action="zoom"] {
  background: var(--x-aqua-gel-zoom);
  border-color: #1d7322;
}

[data-theme="aqua"] [data-part="control"]:active {
  filter: brightness(0.85);
}

/* Glyphs are hidden until the pointer reaches the cluster (any of the three). */
[data-theme="aqua"] [data-part="control"] > span {
  font-size: 10px;
  font-weight: bold;
  line-height: 1;
  color: var(--x-aqua-glyph);
  opacity: 0;
  transition: opacity var(--motion-fast) var(--ease);
  /* Flexbox centres the glyph a hair low for the gel buttons' optical centre;
     nudge the ×/−/+ up 1px so they sit dead-centre. */
  transform: translateY(-1px);
}
[data-theme="aqua"] [data-part="controls"]:hover [data-part="control"] > span {
  opacity: 1;
}

/* Inactive window: all three turn matte gray; hovering the cluster restores
   the gels (the higher-specificity rules below win over the gray). */
[data-theme="aqua"] [data-part="control"][data-focused="false"] {
  background: var(--x-aqua-gel-inactive);
  border-color: #8f8f8f;
}
[data-theme="aqua"] [data-part="controls"]:hover [data-part="control"][data-action="close"] {
  background: var(--x-aqua-gel-close);
  border-color: #9a2b22;
}
[data-theme="aqua"] [data-part="controls"]:hover [data-part="control"][data-action="minimize"] {
  background: var(--x-aqua-gel-minimize);
  border-color: #97700f;
}
[data-theme="aqua"] [data-part="controls"]:hover [data-part="control"][data-action="zoom"] {
  background: var(--x-aqua-gel-zoom);
  border-color: #1d7322;
}

/* ── Toolbar ─────────────────────────────────────────────────────────────── */
[data-theme="aqua"] [data-part="toolbar"] {
  background: var(--toolbar-bg);
  border-bottom: 1px solid var(--toolbar-border);
}

/* Gel pill buttons: white gel face, blue gel when toggled on / menu open. */
[data-theme="aqua"] [data-part="toolbar-button"],
[data-theme="aqua"] [data-part="button"],
[data-theme="aqua"] [data-part="icon-button"] {
  height: 22px;
  padding: 0 10px;
  border: 1px solid var(--control-border);
  border-radius: var(--control-radius);
  background: var(--control-bg);
  color: var(--control-fg);
  box-shadow: var(--control-shadow);
}

[data-theme="aqua"] [data-part="icon-button"] {
  width: 26px;
  padding: 0;
}

[data-theme="aqua"] [data-part="toolbar-button"]:hover,
[data-theme="aqua"] [data-part="button"]:hover,
[data-theme="aqua"] [data-part="icon-button"]:hover {
  background: var(--control-bg-hover);
}

[data-theme="aqua"] [data-part="toolbar-button"]:active,
[data-theme="aqua"] [data-part="button"]:active,
[data-theme="aqua"] [data-part="icon-button"]:active {
  background: var(--control-bg-active);
  box-shadow: var(--x-aqua-inset-shadow);
}

[data-theme="aqua"] [data-part="toolbar-button"][data-state="active"],
[data-theme="aqua"] [data-part="button"][data-state="open"] {
  background: var(--x-aqua-gel-blue);
  border-color: #2a5fbe;
  color: var(--accent-on);
  text-shadow: var(--x-aqua-engrave);
}

/* ── Segmented control (lozenge) ─────────────────────────────────────────── */
[data-theme="aqua"] [data-part="segmented"] {
  border: 1px solid var(--control-border);
  border-radius: var(--control-radius);
  background: var(--control-bg);
  box-shadow: var(--control-shadow);
  overflow: hidden;
}

[data-theme="aqua"] [data-part="segment"] {
  height: 20px;
  padding: 0 12px;
  border-left: 1px solid var(--control-border);
  color: var(--control-fg);
}
[data-theme="aqua"] [data-part="segment"]:first-child {
  border-left: none;
}
[data-theme="aqua"] [data-part="segment"]:active {
  background: var(--control-bg-active);
}
[data-theme="aqua"] [data-part="segment"][data-state="selected"] {
  background: var(--x-aqua-gel-blue);
  color: var(--accent-on);
  text-shadow: var(--x-aqua-engrave);
}

/* ── Breadcrumbs ─────────────────────────────────────────────────────────── */
[data-theme="aqua"] [data-part="breadcrumbs"] {
  color: var(--fg-muted);
}

[data-theme="aqua"] [data-part="breadcrumb"] {
  height: 18px;
  padding: 0 6px;
  border-radius: 9px;
  color: var(--fg);
}
[data-theme="aqua"] [data-part="breadcrumb"]:hover {
  background: var(--x-aqua-hover-wash);
}
[data-theme="aqua"] [data-part="breadcrumb"][data-state="current"] {
  font-weight: bold;
}

/* ── Search field (round Aqua well) ──────────────────────────────────────── */
[data-theme="aqua"] [data-part="search-field"] {
  height: 20px;
  padding: 0 8px;
  border: 1px solid var(--input-border);
  border-radius: 10px;
  background: var(--input-bg);
  box-shadow: var(--x-aqua-inset-shadow);
  color: var(--fg-muted);
}
[data-theme="aqua"] [data-part="search-field"] input {
  color: var(--input-fg);
  font-size: 12px;
}
[data-theme="aqua"] [data-part="search-field"]:focus-within {
  outline: var(--focus-ring);
  outline-offset: 0;
}

/* ── Sidebar ─────────────────────────────────────────────────────────────── */
[data-theme="aqua"] [data-part="sidebar"] {
  background: var(--sidebar-bg);
  color: var(--sidebar-fg);
  padding: 6px 0;
}

[data-theme="aqua"] [data-part="sidebar-heading"] {
  padding: 8px 12px 2px;
  font-size: 11px;
  font-weight: bold;
  color: var(--fg-muted);
  text-shadow: var(--x-aqua-emboss);
}

[data-theme="aqua"] [data-part="sidebar-item"] {
  padding: 0 12px;
  color: var(--sidebar-fg);
}
[data-theme="aqua"] [data-part="sidebar-item-icon"] {
  color: var(--fg-muted);
}
[data-theme="aqua"] [data-part="sidebar-item"][data-state="selected"] {
  background: var(--sidebar-selected-bg);
  color: var(--sidebar-selected-fg);
  text-shadow: var(--x-aqua-engrave);
}
[data-theme="aqua"] [data-part="sidebar-item"][data-state="selected"] [data-part="sidebar-item-icon"] {
  color: var(--sidebar-selected-fg);
}
/* Era rule: selection desaturates to gray in a background window. */
[data-theme="aqua"] [data-part="window"][data-focused="false"] [data-part="sidebar-item"][data-state="selected"] {
  background: var(--x-aqua-selection-grad-inactive);
  text-shadow: none;
}
/* Inline eject on removable-volume rows — the tab-close treatment. */
[data-theme="aqua"] [data-part="sidebar-item-action"] {
  width: 14px;
  height: 14px;
  border-radius: 50%;
  color: var(--fg-muted);
}
[data-theme="aqua"] [data-part="sidebar-item-action"]:hover {
  background: rgba(0, 0, 0, 0.14);
  color: var(--fg);
}
[data-theme="aqua"] [data-part="sidebar-item"][data-state="selected"] [data-part="sidebar-item-action"] {
  color: var(--sidebar-selected-fg);
}

/* The divider's 5px hit area paints a single hairline at its center. */
[data-theme="aqua"] [data-part="split-divider"] {
  background: linear-gradient(
    to right,
    transparent 2px,
    var(--border-strong) 2px,
    var(--border-strong) 3px,
    transparent 3px
  );
}

/* ── File list ───────────────────────────────────────────────────────────── */
[data-theme="aqua"] [data-part="file-list"] {
  background: var(--list-bg);
}

[data-theme="aqua"] [data-part="file-list-header"] {
  background: var(--list-header-bg);
  color: var(--list-header-fg);
  border-bottom: 1px solid var(--border);
  font-size: 11px;
}
[data-theme="aqua"] [data-part="file-list-col"] {
  border-right: 1px solid var(--border);
  text-shadow: var(--x-aqua-emboss);
}
[data-theme="aqua"] [data-part="file-list-col"]:last-child {
  border-right: none;
}
[data-theme="aqua"] [data-part="file-list-col"][data-state="sorted"] {
  background: var(--x-aqua-header-sorted);
}

[data-theme="aqua"] [data-part="file-row"] {
  font-size: 12px;
}
/* Classic Finder stripes: first row white, every second tinted blue. */
[data-theme="aqua"] [data-part="file-row"][data-zebra="even"] {
  background: var(--list-zebra);
}
[data-theme="aqua"] [data-part="file-icon"] {
  color: var(--fg-muted);
}
[data-theme="aqua"] [data-part="file-row"][data-state="selected"] {
  background: var(--x-aqua-selection-grad);
  color: var(--selection-fg);
  text-shadow: var(--x-aqua-engrave);
}
[data-theme="aqua"] [data-part="file-row"][data-state="selected"] [data-part="file-icon"] {
  color: var(--selection-fg);
}
[data-theme="aqua"] [data-part="window"][data-focused="false"] [data-part="file-row"][data-state="selected"] {
  background: var(--x-aqua-selection-grad-inactive);
  text-shadow: none;
}

/* ── Icon grid: Finder-style label pill + icon backplate when selected ───── */
[data-theme="aqua"] [data-part="icon-grid"] {
  background: var(--list-bg);
}
[data-theme="aqua"] [data-part="icon-grid-label"] {
  font-size: 12px;
  padding: 1px 6px;
  border-radius: 8px;
}
[data-theme="aqua"] [data-part="icon-grid-item"][data-state="selected"] [data-part="icon-grid-label"] {
  background: var(--x-aqua-selection-grad);
  color: var(--selection-fg);
  text-shadow: var(--x-aqua-engrave);
}
[data-theme="aqua"] [data-part="icon-grid-item"][data-state="selected"] [data-part="icon-grid-icon"] {
  background: rgba(0, 0, 0, 0.14);
  border-radius: 5px;
}
[data-theme="aqua"] [data-part="window"][data-focused="false"] [data-part="icon-grid-item"][data-state="selected"] [data-part="icon-grid-label"] {
  background: var(--x-aqua-selection-grad-inactive);
  text-shadow: none;
}

[data-theme="aqua"] [data-part="list-empty"] {
  background: var(--list-bg);
  color: var(--fg-disabled);
}

/* ── Terminal panel ──────────────────────────────────────────────────────── */
[data-theme="aqua"] [data-part="terminal-panel"] {
  /* Chrome surface, not terminal black: the resize grip + header are window
     chrome; only the host paints the terminal background. */
  background: var(--surface);
  border-top: 1px solid var(--border-strong);
}
[data-theme="aqua"] [data-part="terminal-panel"][data-state="closed"] {
  border-top: none;
}

[data-theme="aqua"] [data-part="terminal-header"] {
  height: 20px;
  padding: 0 8px;
  background: var(--titlebar-bg);
  border-bottom: 1px solid var(--border);
  font-size: 11px;
  color: var(--fg-muted);
  text-shadow: var(--x-aqua-emboss);
}

[data-theme="aqua"] [data-part="terminal-host"] {
  background: var(--terminal-bg);
  color: var(--terminal-fg);
  font-family: var(--font-mono);
  padding: 4px 6px;
}

/* ── Status bar ──────────────────────────────────────────────────────────── */
[data-theme="aqua"] [data-part="status-bar"] {
  height: 20px;
  justify-content: center;
  background: var(--x-aqua-pinstripe);
  border-top: 1px solid var(--border);
  font-size: 11px;
  color: var(--fg-muted);
  text-shadow: var(--x-aqua-emboss);
}

/* ── Menus ───────────────────────────────────────────────────────────────── */
[data-theme="aqua"] [data-part="menu"] {
  margin-top: 2px;
  padding: 4px 0;
  background: var(--surface-sunken);
  border: 1px solid rgba(0, 0, 0, 0.3);
  border-radius: 5px;
  box-shadow: var(--x-aqua-menu-shadow);
}

[data-theme="aqua"] [data-part="menu-item"] {
  height: 19px;
  padding: 0 20px 0 12px;
}
[data-theme="aqua"] [data-part="menu-item"]:hover,
[data-theme="aqua"] [data-part="menu-item"]:focus-visible {
  background: var(--x-aqua-selection-grad);
  color: var(--selection-fg);
  text-shadow: var(--x-aqua-engrave);
  outline: none;
}
[data-theme="aqua"] [data-part="menu-item"][aria-disabled="true"] {
  background: transparent;
  color: var(--fg-disabled);
  text-shadow: none;
}

[data-theme="aqua"] [data-part="menu-separator"] {
  height: 1px;
  margin: 4px 1px;
  background: var(--border);
}

/* ── Scrollbars (blue gel scroller in a pinstriped track) ────────────────── */
/* Base CSS paints the vertical orientation from --scrollbar-thumb/-track;
   the horizontal orientation needs its gradients rotated. */
[data-theme="aqua"] ::-webkit-scrollbar-thumb {
  border-radius: 8px;
  border: 2px solid transparent;
  background-clip: padding-box;
}
[data-theme="aqua"] ::-webkit-scrollbar-thumb:horizontal {
  background: var(--x-aqua-scroll-thumb-h);
  border: 2px solid transparent;
  background-clip: padding-box;
}
[data-theme="aqua"] ::-webkit-scrollbar-track:horizontal {
  background: var(--x-aqua-scroll-track-h);
}
[data-theme="aqua"] ::-webkit-scrollbar-button {
  display: none;
}
[data-theme="aqua"] ::-webkit-scrollbar-corner {
  background: var(--scrollbar-track);
}

/* ── In-page tabs (⌘T) — Safari 1.0 posture: metal strip, gel document tabs */
[data-theme="aqua"] [data-part="tab-bar"] {
  background: var(--titlebar-bg-inactive);
  border-bottom: 1px solid var(--border-strong);
  padding: 4px 6px 0;
  gap: 3px;
}

[data-theme="aqua"] [data-part="tab"] {
  height: 23px;
  min-height: 23px;
  font-size: 11px;
  color: var(--fg-muted);
  border: 1px solid var(--border-strong);
  border-bottom: none;
  border-radius: 5px 5px 0 0;
  /* Unselected tabs recede into the strip like background gel buttons. */
  background: linear-gradient(#d4d4d4, #c2c2c2 55%, #b9b9b9);
  box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.55);
}

[data-theme="aqua"] [data-part="tab"][data-state="selected"] {
  color: var(--fg);
  background: linear-gradient(#fdfdfd, #ececec 55%, #e3e3e3);
  text-shadow: var(--x-aqua-emboss);
}

[data-theme="aqua"] [data-part="window"][data-focused="false"] [data-part="tab"] {
  color: var(--titlebar-fg-inactive);
}

[data-theme="aqua"] [data-part="tab-label"] {
  text-align: center;
}

[data-theme="aqua"] [data-part="tab-close"],
[data-theme="aqua"] [data-part="tab-add"] {
  width: 14px;
  height: 14px;
  border-radius: 50%;
  font-size: 11px;
  line-height: 1;
  color: var(--fg-muted);
}

[data-theme="aqua"] [data-part="tab-close"]:hover,
[data-theme="aqua"] [data-part="tab-add"]:hover {
  background: rgba(0, 0, 0, 0.14);
  color: var(--fg);
}

[data-theme="aqua"] [data-part="tab-add"] {
  align-self: center;
  margin: 0 2px 4px;
}

/* ── Modal dialogs (Get Info, Go to Folder, New File) ───────────────────── */
[data-theme="aqua"] [data-part="dialog-overlay"] {
  background: rgba(0, 0, 0, 0.12);
}

[data-theme="aqua"] [data-part="dialog"] {
  /* An Aqua alert: white rounded panel floating on a deep soft shadow. */
  background: #f6f6f6;
  border: 1px solid rgba(0, 0, 0, 0.28);
  border-radius: 10px;
  box-shadow: 0 22px 55px rgba(0, 0, 0, 0.5), inset 0 1px 0 rgba(255, 255, 255, 0.9);
}

[data-theme="aqua"] [data-part="dialog-title"] {
  text-align: center;
  font-size: 13px;
  font-weight: 700;
}

[data-theme="aqua"] [data-part="text-input"] {
  border: 1px solid #9a9a9a;
  border-radius: 2px;
  box-shadow: var(--x-aqua-inset-shadow);
  padding: 4px 6px;
}
